patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 6737b50405ee..a104adf74e98 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,38 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq/ne (and (add A, Addend), Msk), 0)
+  //   where Msk = ~P (P is a power of 2)
+  //   -> If A's known bits show that bits outside ((-Addend) & (P-Addend)) and P
+  //      are zero, then A can only be -Addend or P-Addend (differing only in bit P).
+  //      This is equivalent to (A & CommonBits) == CommonBits where
+  //      CommonBits = (-Addend) & (P-Addend).
+  {
+    Value *A;
+    const APInt *Addend, *Msk;
+    if (C.isZero() &&
+        match(And, m_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                         m_APInt(Msk)))) {
+      APInt P = ~(*Msk);
+      if (P.isPowerOf2()) {
+        APInt V1 = -*Addend;
+        APInt V2 = P - *Addend;
+        APInt CommonBits = V1 & V2;
+        if (CommonBits != 0) {
+          // Check that A has no bits outside CommonBits and P that could be set.
+          APInt MustBeZero = ~CommonBits & ~P;
+          KnownBits Known = computeKnownBits(A, And, 0);
+          if (MustBeZero.isSubsetOf(Known.Zero)) {
+            Value *AndA = Builder.CreateAnd(A,
+                ConstantInt::get(A->getType(), CommonBits));
+            return new ICmpInst(Pred, AndA,
+                ConstantInt::get(AndA->getType(), CommonBits));
+          }
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

